Use ASP.NET Core's **`WebApplicationFactory<T>`** — it hosts your app in-process with a test HTTP client, no ports needed.

### Setup

```csharp
// TestFixture.cs
public class McpServerFixture : WebApplicationFactory<Program>
{
    // override ConfigureWebHost if you need test-specific DI
}
```

### Writing Tests

```csharp
public class McpIntegrationTests : IClassFixture<McpServerFixture>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(McpServerFixture fixture)
        => _client = fixture.CreateClient();

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);
        response.EnsureSuccessStatusCode();

        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26", body.GetProperty("result")
            .GetProperty("protocolVersion").GetString());
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        // initialize first, then call tools/call
        await InitializeAsync();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my_tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();

        Assert.False(body.GetProperty("result")
            .GetProperty("isError").GetBoolean());
    }
}
```

### Key points

- **`WebApplicationFactory`** runs your full middleware pipeline (auth, routing, MCP handling) in-memory — no network, no ports.
- Test each JSON-RPC method (`initialize`, `tools/list`, `tools/call`, etc.) as a separate HTTP POST with the standard MCP JSON-RPC envelope.
- For **Streamable HTTP** (SSE responses), use `SendAsync` with `HttpCompletionOption.ResponseHeadersRead` and read the stream line-by-line.
- Mock external dependencies by overriding `ConfigureWebHost` to swap services in DI.
- Add `Microsoft.AspNetCore.Mvc.Testing` to your test project.
